"""
Centralized Icon Repository
All icons use {size} and {color} placeholders for consistent templating.
"""


def get_icon(key, size=24, color="currentColor"):
    """Returns a formatted SVG icon string from the registry."""
    svg_template = ICONS.get(key, "")
    if not svg_template:
        return ""
    return svg_template.format(size=size, color=color)


